#!/usr/bin/env python3
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]

REPLACEMENTS = {
    ROOT / "index.html": (
        '<blockquote class="editorial-quote editorial-quote--author"><p>Часом життя ставить перед нами випробування. Знайди в собі ресурс, щоб їх прийняти.</p><p>У кожній складності прихований урок, у кожній втраті — можливість для нового усвідомлення.</p><p>Відкрий внутрішнє джерело, яке веде тебе вперед, і пам’ятай: справжня сила народжується не лише в перемогах, а й у здатності зберігати віру, любов і гармонію навіть у найважчі моменти.</p><p>Кожне випробування — це крок до глибшого пізнання себе й свого призначення.</p><footer>Аліна Горб · про внутрішню опору</footer></blockquote>',
        '<blockquote class="editorial-quote editorial-quote--author"><p>Часом життя ставить перед нами випробування.</p><p>Знайди в собі ресурс, щоб їх прийняти.</p><p>Кожне випробування — це крок до глибшого пізнання себе й свого призначення.</p><p>У кожній складності прихований урок, у кожній втраті — можливість для нового усвідомлення.</p><p>Відкрий внутрішнє джерело, яке веде тебе вперед, і пам’ятай: справжня сила народжується не лише в перемогах, а й у здатності зберігати віру, любов і гармонію навіть у найважчі моменти.</p><footer>Аліна Горб · про внутрішню опору</footer></blockquote>',
    ),
    ROOT / "ru/index.html": (
        '<blockquote class="editorial-quote editorial-quote--author"><p>Порой жизнь ставит перед нами испытания. Найди в себе ресурс, чтобы их принять.</p><p>В каждой трудности скрыт урок, в каждой потере — возможность для нового осознания.</p><p>Открой внутренний источник, который ведёт тебя вперёд, и помни: настоящая сила рождается не только в победах, но и в способности сохранять веру, любовь и гармонию даже в самые трудные моменты.</p><p>Каждое испытание — это шаг к более глубокому познанию себя и своего предназначения.</p><footer>Алина Горб · о внутренней опоре</footer></blockquote>',
        '<blockquote class="editorial-quote editorial-quote--author"><p>Порой жизнь ставит перед нами испытания.</p><p>Найди в себе ресурс, чтобы их принять.</p><p>Каждое испытание — это шаг к более глубокому познанию себя и своего предназначения.</p><p>В каждой трудности скрыт урок, в каждой потере — возможность для нового осознания.</p><p>Открой внутренний источник, который ведёт тебя вперёд, и помни: настоящая сила рождается не только в победах, но и в способности сохранять веру, любовь и гармонию даже в самые трудные моменты.</p><footer>Алина Горб · о внутренней опоре</footer></blockquote>',
    ),
}

for path, (old, new) in REPLACEMENTS.items():
    text = path.read_text(encoding="utf-8")
    if text.count(old) != 1:
        raise SystemExit(f"Expected exactly one current quote in {path.relative_to(ROOT)}")
    updated = text.replace(old, new)
    if old in updated or updated.count(new) != 1:
        raise SystemExit(f"Quote replacement validation failed in {path.relative_to(ROOT)}")
    path.write_text(updated, encoding="utf-8")

print("Final Ukrainian and Russian author quotes applied")
